arguments.command:
cd /tmp/sv-8128ba6d6c31497987bf30fe8a50041c/symbols

# For the two SGen worker addresses that didn't resolve well, let's find the enclosing function
# using the symbol table
for addr in 0x2f4b20 0x2f4c84; do
  echo "=== $addr ==="
  # Find the nearest function symbol at or below this address
  readelf -sW libmonosgen-2.0.so.dbg | awk -v target="$addr" '
    BEGIN { target_dec = strtonum(target); best_name = ""; best_addr = 0 }
    $4 == "FUNC" {
      addr_dec = strtonum("0x" $2)
      size = strtonum($3)
      if (addr_dec <= target_dec && addr_dec > best_addr) {
        best_addr = addr_dec
        best_size = size
        best_name = $8
      }
    }
    END {
      if (best_name != "") {
        printf "  Function: %s (at 0x%x, size %d, offset +0x%x)\n", best_name, best_addr, best_size, target_dec - best_addr
      } else {
        print "  Not found"
      }
    }
  '
done

