cd /tmp/sv-8128ba6d6c31497987bf30fe8a50041c/symbols

# Let me look at the DWARF aranges to find which function owns these addresses
readelf --debug-dump=aranges libmonosgen-2.0.so.dbg 2>/dev/null | head -40
echo "=== Trying nm approach ==="
# Find the nearest named function symbols
nm -n libmonosgen-2.0.so.dbg 2>/dev/null | awk '
  /^[0-9a-f]+ [tTwW]/ && $3 !~ /^\$/ && $3 !~ /__CortexA53/ {
    addr = strtonum("0x" $1)
    if (addr <= 0x2f4b20) { name1 = $3; a1 = addr }
    if (addr <= 0x2f4c84) { name2 = $3; a2 = addr }
  }
  END {
    printf "0x2f4b20 is in: %s (0x%x, offset +0x%x)\n", name1, a1, 0x2f4b20 - a1
    printf "0x2f4c84 is in: %s (0x%x, offset +0x%x)\n", name2, a2, 0x2f4c84 - a2
  }
'

