arguments.command:
cd /tmp/sv-8128ba6d6c31497987bf30fe8a50041c/symbols

# These addresses are in Cortex-A53 erratum patch stubs. They are branch thunks
# inserted by the linker. Let's find what code they patch (the original branch target).
# Look at nearby function symbols more carefully  
nm -n libmonosgen-2.0.so.dbg 2>/dev/null | awk '
  /^[0-9a-f]+/ {
    addr = strtonum("0x" $1)
    if (addr >= 0x2f4a00 && addr <= 0x2f5000) {
      print $0
    }
  }
' | head -30

echo "=== Check section for these addresses ==="
readelf -S libmonosgen-2.0.so.dbg 2>/dev/null | grep -E "^\s+\[" | awk '{
  if ($2 ~ /^\./) {
    name = $2
    addr = strtonum("0x" $4)
    size = strtonum("0x" $6)
    end = addr + size
    if (0x2f4b20 >= addr && 0x2f4b20 < end) {
      printf "0x2f4b20 in section %s (0x%x - 0x%x)\n", name, addr, end
    }
  }
}'

